from flask import Flask, request, jsonify
import os
import json
import time
import hashlib
from functools import wraps

app = Flask(__name__)
CACHE_DIR = 'cache'
CACHE_EXPIRATION = 60  # seconds

if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(endpoint, *args, **kwargs):
    key = f"{endpoint}:{args}:{kwargs}"
    return hashlib.md5(key.encode()).hexdigest()

def load_cache(key):
    try:
        with open(os.path.join(CACHE_DIR, key + '.json'), 'r') as f:
            data = json.load(f)
            if time.time() - data['timestamp'] < CACHE_EXPIRATION:
                return data['response']
    except (FileNotFoundError, json.JSONDecodeError):
        return None

def save_cache(key, response):
    data = {
        'timestamp': time.time(),
        'response': response
    }
    with open(os.path.join(CACHE_DIR, key + '.json'), 'w') as f:
        json.dump(data, f)

def cache_response(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        key = cache_key(func.__name__, *args, **kwargs)
        cached_response = load_cache(key)
        if cached_response is not None:
            return jsonify(cached_response)
        
        response = func(*args, **kwargs)
        save_cache(key, response.get_json())
        return response
    return wrapper

@app.route('/api/data', methods=['GET'])
@cache_response
def get_data():
    # Simulate an expensive operation
    time.sleep(2)
    response_data = {
        'data': [1, 2, 3],
        'metadata': {'count': 3, 'source': 'expensive_api'}
    }
    return jsonify(response_data)

